mapper.select:
select s.snapshot_id, s.family_id, f.family_name, s.member_id, m.member_name, s.account_id, a.account_name, s.asset_id, t.asset_name, s.snapshot_date, s.quote_time, s.holding_qty, s.cost_amount, s.market_value, s.floating_profit_amount, s.realized_profit_amount, s.profit_amount, s.profit_rate, s.position_ratio from fin_holding_snapshot s left join fin_family f on f.family_id = s.family_id left join fin_member_account m on m.member_id = s.member_id left join fin_holding_account a on a.account_id = s.account_id left join fin_asset t on t.asset_id = s.asset_id inner join ( select family_id, member_id, account_id, asset_id, max(quote_time) as max_quote_time from fin_holding_snapshot group by family_id, member_id, account_id, asset_id ) x on x.family_id = s.family_id and x.member_id = s.member_id and x.account_id = s.account_id and x.asset_id = s.asset_id and x.max_quote_time = s.quote_time
1 = 1 and s.family_id = #{familyId} and s.member_id = #{memberId} and s.account_id = #{accountId}
order by s.quote_time desc
